import React from 'react';

const SparkChart = ({
  data,
  width = 80,
  height = 24,
  color = '#3fb950',
  showLastDot = true,
}) => {
  if (!data || data.length === 0) return null;

  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;

  const points = data.map((d, i) => {
    const x = (i / (data.length - 1)) * (width - 1);
    const y = height - ((d - min) / range) * (height - 1);
    return [x, y];
  });

  const polylinePoints = points.map(p => p.join(',')).join(' ');

  const gradientId = `sparkGradient_${Math.random().toString(36).substr(2, 9)}`;

  return (
    <svg
      width={width}
      height={height}
      style={{ backgroundColor: '#0B0F14', display: 'block' }}
      aria-label="Sparkline chart"
      role="img"
    >
      <defs>
        <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.2" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <polyline
        fill={`url(#${gradientId})`}
        stroke="none"
        points={
          polylinePoints +
          ` ${width - 1},${height - 1} 0,${height - 1}`
        }
      />
      <polyline
        fill="none"
        stroke={color}
        strokeWidth="1.5"
        points={polylinePoints}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      {showLastDot && (
        <circle
          cx={points[points.length - 1][0]}
          cy={points[points.length - 1][1]}
          r="2"
          fill={color}
          stroke="#0F1620"
          strokeWidth="1"
        />
      )}
    </svg>
  );
};

export default SparkChart;
